using UnityEngine;

/// <summary>
/// Corrente térmica (P8 — Arara H2 "ganha altura ao planar"): zona de
/// Collider2D (Trigger) que, enquanto um player a PLANAR (GlideAbility.IsGliding)
/// estiver dentro, aplica uma velocidade vertical ascendente — em vez de só
/// "cair lento" (comportamento normal do Glide), o player GANHA altura.
///
/// Colocar num GameObject com Collider2D marcado como "Is Trigger" sobre a
/// área da corrente (ex.: por cima de uma fonte de calor/vulcão/areal ao sol).
/// </summary>
[RequireComponent(typeof(Collider2D))]
public class ThermalCurrent : MonoBehaviour
{
    [Header("Subida")]
    [Tooltip("Velocidade vertical (m/s) que o player atinge dentro da corrente, enquanto planar.")]
    public float liftSpeed = 4f;

    [Tooltip("Aceleração (m/s²) com que a velocidade vertical actual se aproxima de 'liftSpeed' — suaviza a entrada/saída da corrente.")]
    public float liftAcceleration = 12f;

    [Header("Requisitos")]
    [Tooltip("Se activo, só afecta o player enquanto estiver ACTIVAMENTE a planar (GlideAbility.IsGliding — botão de habilidade premido). Se desactivado, basta a forma ter 'canGlide' (mesmo sem activar o glide).")]
    public bool requireActiveGlide = true;

    private void OnTriggerStay2D(Collider2D other)
    {
        if (!other.CompareTag("Player")) return;

        var glide = other.GetComponent<GlideAbility>();
        if (glide == null) return;

        if (requireActiveGlide)
        {
            if (!glide.IsGliding) return;
        }
        else
        {
            var switcher = other.GetComponent<FormSwitcher>();
            var form = switcher != null ? switcher.CurrentForm : null;
            if (form == null || !form.canGlide) return;
        }

        var rb = other.GetComponent<Rigidbody2D>();
        if (rb == null) return;

        float newVy = Mathf.MoveTowards(rb.velocity.y, liftSpeed, liftAcceleration * Time.deltaTime);
        rb.velocity = new Vector2(rb.velocity.x, newVy);
    }

    private void OnDrawGizmos()
    {
        var col = GetComponent<Collider2D>();
        if (col == null) return;

        Gizmos.color = new Color(1f, 0.5f, 0.1f, 0.35f);
        Gizmos.DrawCube(col.bounds.center, col.bounds.size);
    }
}
